form:Form.form:Scripts:
		function EnableButtons()
{
	if (Ctrl("lblERROR").GetXValue()!="" || Ctrl('f_desde_solicitud').GetXValue() == "" || Ctrl('f_hasta_solicitud').GetXValue() == ""  || Ctrl('e_dias_solicitud').GetXValue() == "")
	{
		CtrlEnabled("btnGuardar",false);
		CtrlEnabled("btnAprobar",false);            
		CtrlEnabled("btnAutorizar",false);		
	} 
	else
	{
		CtrlEnabled("btnGuardar",true);
		CtrlEnabled("btnAprobar",true);
		CtrlEnabled("btnAutorizar",true);
	}	
}

function SetControls()
{
	Ctrl('l_automatica').SetXValue("1");
	CtrlEnabled("e_dias_bonif",false);
	EnableButtons();
}

function CALCULAR_DIAS()
{
	if(Ctrl('l_automatica').GetXValue() == "1") 
	{
		if (Ctrl('f_desde_solicitud').GetXValue() == "" || Ctrl('f_hasta_solicitud').GetXValue() == "")
		{
			Ctrl('e_dias_solicitud').SetXValue("");
			EnableButtons();
		} 
		else
			Ctrl('main').DoEvent('RECALCULAR_DIAS');
	}
	else
	{
		EnableButtons();
	}	
}

function CALCULAR_F_HASTA()
{
	if(Ctrl('l_automatica').GetXValue() == "1") 
	{
		if (Ctrl('f_desde_solicitud').GetXValue() == "")
			EnableButtons();
		else
			Ctrl('main').DoEvent('RECALCULAR_FECHA');
	}
	else
	{
		EnableButtons();
	}
}

function ChgAuto()
{           
	Ctrl('f_desde_solicitud').SetXValue("");
	Ctrl('f_hasta_solicitud').SetXValue("");	
	Ctrl('e_dias_solicitud').SetXValue("");
	Ctrl('e_dias_bonif').SetXValue("");
	if(Ctrl("e_dias_bonif").GetEnabled())
		CtrlEnabled("e_dias_bonif",false);
	else
		CtrlEnabled("e_dias_bonif",true);	

	EnableButtons();
}                   

function CALCULAR_SUPERPOSICION()
{
	var np = new NomadProxy();
	var nSQL = np.SQLService(); 
	result= nSQL.GetOBJ(Ctrl("main").getResource("QRY_GRUPO_LEGAJO"),"<PARAM oi_personal_emp=\""+Ctrl("oi_personal_emp").GetXValue()+"\" f_desde_solicitud=\""+Ctrl("f_desde_solicitud").GetXValue()+"\" f_hasta_solicitud=\""+Ctrl("f_hasta_solicitud").GetXValue()+"\" />");      

	if(result.legajo_sup)
		{
			var msg="La solicitud de vacaciones realizada se superpone "+result.dias_sup.toString();
			msg=msg+" días con la licencia de otro legajo.";
			msg=msg+" Esta superposición se encuentra FUERA del rango permitido, por lo tanto, no puede generar dicha solicitud. \n \n";
			msg=msg+"Legajo: "+result.legajo_sup.toString()+"\n";   
			msg=msg+"Fecha de Inicio: "+result.f_inicio_sup.toString()+"\n";
			msg=msg+"Fecha de Fin: "+result.f_fin_sup.toString()+"\n \n"; 
			alert(msg); 
			return false;  
		}
	else if (result.legajo)
	 		{
	 		var msg="Advertencia! \n";
			msg=msg+"La solicitud de vacaciones realizada se superpone "+result.dias.toString();
			msg=msg+" días con la licencia de otro legajo.";
			msg=msg+" Esta superposición se encuentra dentro del rango permitido. \n \n";
			msg=msg+"Legajo: "+result.legajo.toString()+"\n";   
			msg=msg+"Fecha de Inicio: "+result.f_inicio.toString()+"\n";
			msg=msg+"Fecha de Fin: "+result.f_fin.toString()+"\n \n"; 
			msg=msg+"¿Desea continuar de todos modos?";
			return confirm(msg);
	 		}               
	 	  else
	 	  	return true;

}        

function ValDates()
{             

  		var licVal;  
		var nSQL = GetProxy().SQLService();
		licVal = nSQL.GetXML(Ctrl("main").getResource("qry_ValLic"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" f_desde_solicitud=\""+Ctrl('f_desde_solicitud').GetXValue()+"\" f_hasta_solicitud=\""+Ctrl('f_hasta_solicitud').GetXValue()+"\"/>");



		if(licVal.GetAttr("flag") != "0")
		{                                			
			var xmlRow;
			var msg="La licencia se solapa con:\n";
			for(xmlRow = licVal.FirstChild(); xmlRow!=null; xmlRow=xmlRow.Next()) 
			{
				msg = msg + xmlRow.GetAttr("desc") + "\n";
			}
			alert(msg);
			return false;	
		}
		else
			return CALCULAR_SUPERPOSICION();
}
